const Q_GOVERNMENT_2016=[{"id": "objective>Government>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A system of government in which the component units are normally stronger than the centre is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">unitary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">confederalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">federalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">quasi-federalism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Confederation may be defined as a loose political arrangement in which autonomous or soveriegn states or republics come together to form a Union in which almost the major functions of government are reserved exclusively for the component states with a weak centre. The component states hold major powers except the common currency, defence, foreign affairs etc in which the central or national government may hold power. The component states refrain from sovereignty, identity, own army, police, and have the constitutional rights to secede from the confederation e.g Senegambia which was a confederation made of sovereign Gambia and Senegal. Confederation of states tend to be established for dealing with critical issues, such as defence.  <br/>  The political philosopher Emmerich Vattel observed \"several sovereign and independent states may unite themselves together by a perpetual confederacy without each in particular ceasing to be a perfect state. Other examples of historical confederations are Granadine confederation (1858 - 1863), Confederation of Central America(1842 - 1844)</div>", "topic": "STRUCTURES OF GOVERNANCE : FEDERAL FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS"}, {"id": "objective>Government>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Amending the constitution is the function of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">civil service</div>", "<div style=\"font-family:Cambria;font-size:17px;\">civil society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Legislature is an arm of government that is assigned the function of law-making. The legislature is given different names in different countries like National or State Assembly as in Nigeria, Parliament as in Britain, Congress as in United States etc. The legislature is responsible for the amendment of the constitution whenever it is deemed necessary. For this purpose, legislature has to pass special laws called amendments in accordance with the procedure laid down in the constitution. In some states, the requirement is that the Legislature must pass the amendment with 2/3rd or 3/4th or an absolute majority of votes.</div>", "topic": "CONSTITUTION : TYPES OF CONSTITUTION"}, {"id": "objective>Government>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Community Tribunal is an organ of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">UN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AU</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OPEC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ECOWAS Court of Justice is an organ of the Economic Community of West African States (ECOWAS), a regional integration community of 15 member states in Western Africa. <br/> Location: Abuja, Nigeria <br/> Judge term length: 4 years <br/> Established: 2001</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OAU/AU"}, {"id": "objective>Government>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was set up by the OAU in pursuit of independence for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Council of Ministers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Commission of Mediation, Conciliation and Arbitration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The General Secretariat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Liberation Committee</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The liberation committee is an organ of the OAU designed to serve the objective of African liberation. The emergence of the OAU was a compromise between revolutionary and functional schools of thought on African liberation. The working of the ALC reflected this compromise. Its preamble stated that in the case of those colonial territories where the colonial power had accepted the principle of independence, and had shown manifest signs of pursuing this goals, members of the committee and the colonial powers concerned should use their good offices to hasten the achievement of representative government and independence by peaceful and constitutional means. \"If however, the colonial powers showed no sign or willingness to recognise the right of the people concerned to self-determination and independence, the committee would seek all means at its disposal to help in the achievement of independence. This was the Addis Ababa Summit conference of the African States in May  1963, which resolved to speed up the liberation struggle of the African people who were then under foreign or white domination.\"</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OAU/AU"}, {"id": "objective>Government>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A benefit of membership of the Commonwealth is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">free visa to Britain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technical assistance for member states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free movement of persons within member states</div>", "<div style=\"font-family:Cambria;font-size:17px;\">free trade amongst member states</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Commonwealth is a voluntary association of the independent countries of the former British Empire. Former British colonies of Canada, Australia, New Zealand, New Found land and South Africa were granted responsible and representative governments in the 19th century. From 1907, these countries with representative governments started regular meetings known as \"Imperial conferences\" in London. One of the Benefits of Technical Assistance i.e Member nations of the Commonwealth seek and obtain technical assistance from other member nations. Technical experts from one member - nation can be dispatched to other member-nations to give technical assistance.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : COMMONWEALTH"}, {"id": "objective>Government>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Union of Teachers is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic pressure group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">professional pressure group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social pressure group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotional pressure group</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria Union of Teachers is a major trade Union in Nigeria. It was formed to create a united front for practitioners of the teaching profession in the country. Major objectives of the union covers the improvement in economic conditions of teachers, an avenue for bringing forth ideas about the educational development of the country from the perspectives of teachers and general economic security for teachers in the country. NUT was inaugurated in 1931. It came about partly as a result of vulnerabilities exposed by the great depression, which led to cuts in teachers salaries and a seemingly lack of Job security. NUT is a professional pressure group in Nigeria.</div>", "topic": "PRESSURE GROUPS"}, {"id": "objective>Government>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of a written constitution is that it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promotes flexibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is easy to amend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensures stability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhances judicial independence</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A written constitution refers to when the whole body of fundamental laws, customs, conventions, principles, rules, regulations according to which a particular government of a country operates are written or documented down countries that practice written constitution include USA, Nigeria, India, France etc. The English protectorate that was set up by Oliver Cromwell after the English Civil war promulgated the first detailed written constitution adopted by a Modern State. It was called the instrument of government. This formed the basis of government for the short-lived republic from 1653 to 1657. One merit of written constitution, however, is that it ensures stability i.e consistency</div>", "topic": "CONSTITUTION"}, {"id": "objective>Government>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Local governments raise funds through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">income tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excise duty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">company tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">property tax</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Local governments raise funds primarily through property taxes. Property tax is a levy on property that the owner is required to pay. The tax is levied by the governing authority of the jurisdiction in which the property is located. This can be a national government, a federated state, a county or geographical region or a municipality.</div>", "topic": "LOCAL GOVERNMENT"}, {"id": "objective>Government>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The power of a government to make policies is an attribute of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">charismatic authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traditional authority</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judicial power</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Political Authority is the power bestowed on a group of individuals by a written document such as constitution to make decisions and policies and enforce obedience.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Normative power is power acquired through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">induction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intuition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">force</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Normative power is power exerted on an individual by a reference group to conform to the group's (or generally accepted) norms of behaviour. Normative power refers to the power of governing the creation, depletion or modification of norms within a system or society and thus entails a strong power of attraction.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The prime minister in the emirate system was the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Madawaki</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Galadima</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waziri</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sarkin Fada</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Emirate, the caliphate was divided into emirates and each headed by an Emir. He had the responsibility of making laws enforcing them and maintaining peace and order in his Emirate. He was believed to have divine rights to rules.  <br/> However, each emir was assisted in the administration of the emirate by a number of advisers. The Waziri was the head of all officials, known to be the Prime minister. He is also the Emir's administrative adviser. </div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An effective instrument of controlling public corporations in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">executive supervision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislative oversight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">managerial supervision</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judicial review</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">By legislative oversight, public corporations will be better managed as the body is responsible for law making and control of public expenditure thereby wielding an effective method towards reducing embezzlement.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : DEREGULATION, PRIVATIZATION, COMMERCIALIZATION – OBJECTIVES, FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Civil Service is the bedrock of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure groups </div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judiciary</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Civil Service is a body or department in the executive arm of government responsible for the execution of the policies and programmes of the government. In Nigeria, there are federal and state Civil services, with each state in Nigeria having its own. The Civil Service remains intact no matter the government in power, though there is slight modification in Nigeria Civil Service.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major aim of privatization in Nigeria is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">empower private individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure efficient service delivery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the work-load of government</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is the transfer of ownership, property or business from the government to the private sector. The government ceases to be the owner of the entity or business. The process in which a publicly traded company is taken over by a few people is also called privatization. The major objective of privatization is to bring about efficiency in service delivery e.g Power Holding Company of Nigeria(PHCN)</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS"}, {"id": "objective>Government>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formation of ECOMOG was spearheaded</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Muhammadu Buhari</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sani Abacha</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibrahim Babangida</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abdulsalami Abubakar</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria was committed to a functional ECOWAS and this led to Babangida's three years tenure as ECOWAS chairman. His government also re-established diplomatic ties with Isreal. In the area of conflct resolution and peace keeping operation, Nigeria was very attractive. Troops and policemen were deployed to various trouled-spots worldwide. The establishment of ECOWAS monitoring Group (ECOMOG) is a credit to the vision of President Babangida.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS"}, {"id": "objective>Government>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A political ideology that gives prominence to land ownership is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">socialism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">capitalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">communism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudalism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Feudalism is a primitive system of government and economic system based mainly on hierarchical order of ownership of land. In this system of government which was practiced in Western Europe in the middle ages, ownership of Land was vested in the King or Monarch or Emperor who also controlled all land users. The land owners sublet the land to their subjects who must in return render services like work for certain days for the land land owners, fight on his behalf etc.  <br/> This system of government called feudalism which is of decentralized oligarchy based on land ownership was also practise in Asia and Africa.</div>", "topic": "POLITICAL IDEOLOGIES : FEUDALISM"}, {"id": "objective>Government>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was introduced by the Buhari Regime?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">SAP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">WAI-C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SFEM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">WAI</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Buhari regime introduced the War Against Indiscipline and Corruption (WAI-C). The WAI-C was a campaign started by the Buhari regime to address the issues of indiscipline, corruption, and other social vices in Nigeria.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The personification of the throne and sovereignty of the state in one individual is the feature of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oligarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aristocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monarchy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monarchy is a system of government in which one person reigns, usually a king or queen. The authority, or crown, in a monarchy is generally inherited. The ruler, or monarch, is often only the head of state, not the head of government. Monarchy is a political system based upon the undivided sovereignty or rule of a single person. It was during the 12th century that kings evolved into rulers of people and territories with defined borders.</div>", "topic": "FORMS OF GOVERNMENT : MONARCHY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The committee that recommended the 1976 Local Government Reforms is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jerome Udoji</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Liman Ciroma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibrahim Dasuki</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Akinola Aguda</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The 1976 Local Government Reforms in Nigeria were recommended by a committee headed by Alhaji Liman Ciroma. The reforms were aimed at standardizing the local government system in the country, making it a third tier of government, and giving it a set of uniform laws, structures, and functions across the country.</div>", "topic": "LOCAL GOVERNMENT"}, {"id": "objective>Government>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under the 1960 Independence Constitution, the Nigerian judiciary did not</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there was no supreme court in Nigeria</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Privy Council in London was the last court of appeal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there were no qualified judges to head the judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the judges were mainly British</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Independence constitution of 1960 which came into force on October 1, 1960 made Nigeria a full fledged sovereign state within the Commonwealth of Nations. However, one weakness of the 1960 independence constitution was that the Supreme Court was not the court of last resort. The Judicial Committee of the Privy Council in Britain continued to act as the highest court of Appeal for Nigeria and was the last-court of Appeal.</div>", "topic": "JUDICIARY"}, {"id": "objective>Government>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following political parties was formed as a result of the elective principle of the Clifford Constitution</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NNDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NCNC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NYM</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NPC</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian National Democratic Party (NNDP) was regarded as the first political party that was formed in Nigeria. The elective principle introduced by the Clifford Constitution of 1922 which allocated three seats to Lagos gave rise to the formation of NNDP in 1923. NNDP was led by Herbert Macaulay regarded as the Father of Nigerian Nationalism. The party was exclusively based in Lagos and no national colouration as its name claimed. It won all the three seats allocated to Lagos in the Legislative council in the elections of 1923, 1928 and 1933. NNDP dominated Lagos for about 15 years. The political activities and campaigns of NNDP were aided by a newspaper called Lagos Daily News launched in 1925 which acted as an arm of the party.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : HUGH CLIFFORD CONSTITUTION 1922"}, {"id": "objective>Government>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the colonial era, the Indirect Rule Policy was not successful in Eastern part</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it was not well understood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the people were not used to centralised leadership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only few British officers were posted to the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the elite were party to the policy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When indirect rule was introduced in the Eastern region, there were no real people of local influence and authority like the Obas and Emirs in the Northern and Western regions respectively, who could be used to carry out the system. In a bid to solve this problem of single rulers, Lord Lugard appointed traditional rulers called \"Warrant chiefs\". The use of these unpopular chiefs and the system of taxation in an effort to raise fund for the prosecution of indirect rule led to among other disturbances the famous Aba women riots of 1929. However, the indirect rule policy was unsuccessful in the East due to the type of political administration practised i.e the Ibo political system of administration was highly decentralised and that contributed immensely to the failure of indirect rule. This type of aministration did not give room for central decision making body.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH COLONIAL ADMINISTRATIVE POLICY – DIRECT AND INDIRECT RULE"}, {"id": "objective>Government>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The focus of Nigeria's foreign policy during Murtala</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total liberation of Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberation of the Southern Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total industrialization of the continent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nationalization of foreign investments</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The height of radicalism during the Muritala/Obasanjo era (1995 - 1979) was reflected. Regarding South Africa, Nigeria had always associated the liberation movements, especially the ANC of Nelson Mandela and Oliver Tambo and PAC (Pan African Congress) of Robert Sobukwe.</div>", "topic": "FOREIGN POLICY : DEFINITION AND PURPOSE"}, {"id": "objective>Government>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement that fought against the conversion of native land to grow </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pan African Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aborigines' Rights Protection Society</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian Youth Movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National COngress of British West Africa</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Gold coast Aborigines' Rights Protection society was an association critical of colonial rule formed in 1897 in the Gold coast, now Ghana. Originally formed by traditional leaders and the educated elite to protect the crown lands. The Bill of 1896 and the Lands Bill of 1897 that threatened traditional land tenure. The Aborigines' Rights protection society became the main political organisation that led organised and sustained opposition against the colonial government, laying the foundation for political action that would ultimately lead to Ghanaian independence.</div>", "topic": "PRE-COLONIAL POLITICS : OTHER PRE-COLONIAL SYSTEMS IN NIGERIA"}, {"id": "objective>Government>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Irikefe Panel recommended an increase in the number of states in Nigeria to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">21</div>", "<div style=\"font-family:Cambria;font-size:17px;\">19</div>", "<div style=\"font-family:Cambria;font-size:17px;\">36</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Murtala Mohammed in 1975 after coming to power set up the Justice Ayo Irikefe Panel or commission to submit recommendations for the creation of additional states in Nigeria. Justice Irikefe Swith some marital ties to Ondo town had recommended the creation of 7 additional states with Ondo state as one thereby increasing the number of states to 19.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : OLIVER LYTTLETON CONSTITUTION 1954"}, {"id": "objective>Government>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following political parties in Nigeria formed an alliance preparatory to the 1964 general election?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NPC and NEPU</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AG and UMBC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NCNC and UMBC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NCNC and AG</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In preparation for the 1964 general elections in Nigeria, the Northern People's Congress (NPC) and the Northern Elements Progressive Union (NEPU) formed an alliance. This alliance was known as the Nigerian National Alliance (NNA).</div>", "topic": "POLITICAL PARTIES AND PARTY POLITICS IN POST-INDEPENDENCE NIGERIA : FIRST REPUBLIC"}, {"id": "objective>Government>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Britain ruled her colonies through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indignant system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct rule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">policy of assimilation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect rule</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Britain ruled her colonies through indirect rule which is a system of ruling her colonies with the use of local chiefs or other appointed intermediaries and traditional laws and customs with British officials merely supervising the administration. Indirect rule was introduced by Sir Lord Lugard who described the system of administration as a \"Child of necessity\". Lord Lugard regarded as the 'Father of Indirect rule' introduce the system in Nigeria around 1906 first in Northern Nigeria when he was the High Commissioner of the protectorate of Northern Nigeria.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH COLONIAL ADMINISTRATIVE POLICY – DIRECT AND INDIRECT RULE"}, {"id": "objective>Government>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Unification Degree No 34 was promulgated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Murtala Mohammed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yakubu Gowon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Olusegun Obasanjo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aguiyi Ironsi</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Unification Decree no of 24 was promulgated by Aguiyi Ironsi and subject to the provisions of this decree, Nigeria shall on 24th May 1966,(in the decree referred to as \"the appointed day\") cease to be a federation and shall accordingly as from that day be a republic by the name of the Republic of Nigeria, consisting of the whole of the territory which immediately before that day was comprised in the Federation.</div>", "topic": "CONSTITUTIONAL DEVELOPMENT IN NIGERIA : OLIVER LYTTLETON CONSTITUTION 1954"}, {"id": "objective>Government>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is associated with the power of the British Monarch?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Statutory instruments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Special Order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bye-law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Order-in-Council</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Order-in-council is an order having the full force of law that is issued by the British monarch acting by and with the advice of the Privy Council or similar body of a member nation of the British Commonwealth. It is usually as a means of giving legal effect to a decision of the cabinet in areas not involving parliamentary action.</div>", "topic": "ARMS OF GOVERNMENT : EXECUTIVE-TYPES, FUNCTIONS AND POWERS"}, {"id": "objective>Government>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organs of the UN ratifies application for membership?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Secretariat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trusteeship Council</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Assembly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Security Council</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The General Assembly of the United Nations ratifies applications for membership. The process of becoming a Member of the UN begins with a letter of application from a country to the Secretary-General. This letter is then passed to the Security Council, where it must receive the affirmative votes of at least 9 of the 15 members, including the concurring votes of all 5 permanent members. If the Council recommends the applicant State for membership, the recommendation is presented to the General Assembly for consideration. A two-thirds majority vote is necessary in the Assembly for admission of a new State.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : UNO"}, {"id": "objective>Government>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The formation of the West African Students' Union was spearhead by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ladipo Solanke</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H.O. Davies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kwame Nkrumah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Herbert Macaulay</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The West African Students' Union (WASU) was formed in London, 1925 under the leadership of chief Ladipo Solanke. It was the social and political activities in which modern militant nationalist was born. Marcus Garvey gave WASU its first hostel in Britain- where it started publishing its journal and nationalist write-ups. The union became the centre of social and political activities, and provided a rallying point for militant nationalists in and around London.</div>", "topic": "IMPERIALIST PENETRATION : THE BRITISH PROCESS OF ACQUISITION – TRADE, MISSIONARY ACTIVITIES, COMPANY RULE, CROWN COLONY, PROTECTORATE"}, {"id": "objective>Government>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sale of government properties in Nigeria is undertaken by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bureau for Public Procurement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Bureau of Statistics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bureau for Public Enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">National Council on Privatisation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Bureau of Public Enterprises (BPE) serves as a secretariat of the National council on Privatisation (NCP) and is charged with the overall responsibility of implementing the council's policies on privatisation and commercialisation. One of its functions is to carry out all activities required for the successful issue of shares and sales of assets of the public enterprises to be privatised.</div>", "topic": "PUBLIC CORPORATIONS AND PARASTATALS : DEREGULATION, PRIVATIZATION, COMMERCIALIZATION – OBJECTIVES, FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mid-Western Region was created in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1976</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1967</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1979</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1963</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mid-western Region was a division of Nigeria from 1963 to 1991, from 1976, being known as the Bendel state. It was formed in June 1963 from Benin and Delta provinces of the Western region, and its capital was Benin city. It was renamed a Province in 1966 and in 1967 when the other provinces were split up into several states, it remained territorially intact, becoming a state. During the Nigerian civil war, the Biafran forces invaded the new mid-western state enroute to Lagos, in an attempt to force a quick end to the war. While Under Biafran Occupation, the state was declared \"Republic of Benin\". As Nigerian forces retook the region, the republic collapsed only a day after the declaration when Nigerian troops captured Benin city. In 1976, the state was renamed Bendel. Bendel state was divided into Delta and Edo state in 1991.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : CREATION OF STATES – 1963, 1967, 1976, 1987, 1991, 1996"}, {"id": "objective>Government>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The adoption of federalism in Nigeria was necessitated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cultural diversity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal size of the regions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">similar resource endowment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the desire for unity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Federalism is a system of government in which governmental powers that exist in a country are shared between a central government that represents the whole country and government of component regions or states so that each state so is constitutionally independent and autonomous. Nigerian Federalism can be traded back to 1914 when the Northern and southern protectorates were amalgamated though with unitary form of administration. Federalism was necessitated mainly by differences in culture, religion, language, custom, tradition etc among different ethnic group.</div>", "topic": "THE STRUCTURE AND WORKINGS OF NIGERIAN FEDERALISM : RATIONALE FOR A FEDERAL SYSTEM"}, {"id": "objective>Government>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major feature of a state is the existence of a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">president</div>", "<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political party</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A state is defined as a political organised body of people occupying a definite geographical territory with an organised government entirely free from external control and with coerce power to secure obedience from its citizens and others. Examples of states are Nigeria, Togo, Gambia, USA, Ghana etc. One of the features of a state must have a machinery called government, that will steer its affairs. Government performs its functions on behalf of the state. The existence and survival of a state are maintained by the government.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : SOCIETY, STATE, NATION AND NATION-STATE"}, {"id": "objective>Government>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The existence of opposition parties in a political system is a feature of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">autocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">democracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fascism</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Democracy is a system of government in which all qualified adult citizens share the supreme power directly or through their elected representatives. Abraham Lincoln defined it as \"the government of the people, by the people and for the people\" The fusion of two greek words \"Demos\"  (people) and Kralia (rule or government) gave birth to the word democracy. However, the existence of opposition parties is a feature of democracy.</div>", "topic": "FORMS OF GOVERNMENT : DEMOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public opinion acts as a guide to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">president</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass media</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Public opinion may be defined as the collective beliefs, judgements or views held by majority of citizens of a country about public polity or action of the government. It therefore refers to what members of the public think or feel about government proposed policy or action already taken by government. Examples of public opinions/issues Nigerians expressed their opinions were on the issues of whether abortion should be legalised in the Second Republic etc.</div>", "topic": "PUBLIC OPINION"}, {"id": "objective>Government>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The credibility of the electoral process is enhanced by the existence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ombudsman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">independent judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transparent electoral body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure groups</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An Electoral commission is a body charged with the responsibility for organizing and conducting Free and Fair elections in a country. The electoral commission is headed by an individual known as the chairman. The appoint of members of the commission is for a fixed period of time. Electoral commissions take different names line in Nigeria it was called Federal Electoral Commision (FEDECO) in the secind and in the third Republic, National Electoral commission. In the Fourth Republic, it is called Independent National Electoral Commission (INEC), co-editility of electoral process is enhanded by a transparent electoral body in a country.</div>", "topic": "ELECTORAL PROCESS"}, {"id": "objective>Government>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these is NOT a means of acquiring citizenship?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Marriage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conquest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conferment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Residency</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Citizenship can be acquired through several means such as birth, naturalization (which includes residency and conferment), marriage, and descent. However, conquest is not a recognized means of acquiring citizenship. Conquest refers to the acquisition of a territory through force, and it does not automatically confer citizenship to the conqueror.</div>", "topic": "CITIZENSHIP : MEANING AND TYPES"}, {"id": "objective>Government>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One reason for the formation of ECOMOG is the need for the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protection of ECOWAS leaders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion of free movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion of regional security</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promotion of technical cooperation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS Monitoring Group (ECOMOG) was formed by the member-nations of ECOWAS-Nigeria, Ghana, Sierra Leone and Guinea as a peace keeping force to mediate in Liberia crisis with the primary mission of separating the warring functions. </div>", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS"}, {"id": "objective>Government>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Secretary-General of OPEC is appointed for a period of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">four years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three years</div>", "<div style=\"font-family:Cambria;font-size:17px;\">five years</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Secretary General is appointed by the Conference from a Member Country for a period of three years, a term of office that may be renewed once for the same period of time.</div>", "topic": "INTERNATIONAL ORGANIZATIONS : OPEC"}, {"id": "objective>Government>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following political ideologies promotes \"We-feelings\" in a society?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aristocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Communalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capitalism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oligarchy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Communalism is a system of collective ownership of property and co-operation among members of a community in the execution of development projects in a communal community, members pursue a common goal collectively, ideologies like \"we feelings\" can be promoted in communalism.</div>", "topic": "POLITICAL IDEOLOGIES : COMMUNALISM"}, {"id": "objective>Government>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an advantage of a federal system of government?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fusion of powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Collective responsibility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Separation of powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Devolution of powers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A federal system of government is one in which governmental power that exist in the country are shared between a central government that represents the whole country and government of component regions or states, so that each government is legally and constitutionally independent and autonomous. Examples of countries that adopt federalism include USA, Nigeria, Federal Republic of Germany etc. One merit is that it devolves or shares powers among the tiers of government. <br/> </div>", "topic": "FORMS OF GOVERNMENT : FEDERAL (FEATURES, REASONS FOR ADOPTION, MERITS AND DEMERITS)"}, {"id": "objective>Government>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Political culture is mainly determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethnicity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political parties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the family</div>", "<div style=\"font-family:Cambria;font-size:17px;\">religious group</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A political culture is a set of attitudes and practices held by a people that shapes their political behavior. It includes moral judgments, political myths, beliefs, and ideas about what makes for a good society. ... Political cultures matter because they shape a population's political perceptions and actions. <br/> Political culture is the attitudes, sentiments, belief, ideas and norms that guide the behaviours of the people in a political system. One determinant of political culture is different Political parties i.e the belief system of each tribe has major impact on the people's political culture. It brings about the differences of political culture.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POLITICAL SOCIALIZATION, POLITICAL PARTICIPATION AND POLITICAL CULTURE"}, {"id": "objective>Government>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Heredity as a basis of political power is a prominent attribute of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">aristocracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oligarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geventoeracy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monarchy may be defined as a form of government under the rule of king, queen or emperor known as monarch. Monarchy is a dynastic system of rule in which the monarch is succeeded by his or her children and power is transferred from generation to generation. Hence, it is hereditary in nature.</div>", "topic": "FORMS OF GOVERNMENT : ARISTOCRACY FEATURES, MERITS AND DEMERITS"}, {"id": "objective>Government>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Sokoto Jihad under the leadership of Uthman Dan Fodio took place in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1804</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1860</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1830</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1904</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sokoto Jihad of Uthman Dan Fodio took place in 1804. The defeat of the Hausas in a Holy War by the Fulanis under the able leadership of a Great Muslim leader, Uthman Dan Fodio, led to the abolition of the Hausa Kingdoms and the establishment of the Fulani emirates.</div>", "topic": "PRE-COLONIAL POLITICS : HAUSA PRE-COLONIAL SYSTEM"}, {"id": "objective>Government>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The interpretation of the constitution is a duty of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">legislature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">judiciary</div>", "<div style=\"font-family:Cambria;font-size:17px;\">executive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">police</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Judiciary is the third organ of government responsible for interpretation and application of the laws when they are broken or violated. It also adjudicates in disputes between the executive and the legislative and between government and the citizens and organisations or among citizens or organisations.  <br/>  The Judiciary is made up of different courts like the Supreme court, the Appeal court, High courts, Magistrate courts, Customary courts, Administrative courts and tribunals.</div>", "topic": "ARMS OF GOVERNMENT : JUDICIARY FUNCTIONS, POWERS AND COMPONENTS"}, {"id": "objective>Government>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Ombudsman was first introduced in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Norway</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Denmark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Great Britain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sweden</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Ombudsman is the institution established to investigate and deal with cases of mal-administration, injustice, corruption and unfair treatment by public officers or public authorities against citizens. The Ombudsman, also known as the public complaints commission was first introduced in Sweden in 1809 and has since been established in many other countries like Finland, Denmark, Norway, Germany etc.</div>", "topic": "BASIC CONCEPTS OF GOVERNMENT : POWER, AUTHORITY, LEGITIMACY AND SOVEREIGNTY"}, {"id": "objective>Government>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important ingredient of the civil service is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hierarchy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">imbalance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nepotism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">partisanship </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An important feature of civil service is hierarchy. This implies that promotions are given as at when due and there is an organogram guiding the civil service.</div>", "topic": "THE CIVIL SERVICE"}, {"id": "objective>Government>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a one-party state,</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">only one party is legally allowed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">only one political party wins elections</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only one party meets the electoral requirement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">every citizen must belong to it</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One-party system may be defined as a political system in which only one political party is legally and constitutionally allowed to operate or through gradual elimination of other political parties through the electoral parties through the electoral processes.  <br/>  <br/> A one-party state is a form of government where the country is ruled by a single political party, meaning only one political party exists and the forming of other political parties is forbidden</div>", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS"}];
